class Solution {
    public int findBestValue(int[] arr, int target) {
        int max = Arrays.stream(arr).max().getAsInt();
        int min = Arrays.stream(arr).min().getAsInt();
        int sum = Arrays.stream(arr).sum();
        int best = min;
        int bestDiff = Math.abs(target - sum);
        for (int i = min; i <= max; i++) {
            int newSum = sum - (sum / i) * i;
            int diff = Math.abs(target - newSum);
            if (diff < bestDiff) {
                bestDiff = diff;
                best = i;
            } else if (diff == bestDiff && i < best) {
                best = i;
            }
        }
        return best;
    }
}
